var input = inputs.Length > 0 ? inputs[0] : null;
if (input is null)
    return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

var channel = GetChoice(parameters, "channel", "RGB");

// Master controls
var inBlack = GetFloat(parameters, "inBlack", 0f);
var inWhite = GetFloat(parameters, "inWhite", 1f);
var outBlack = GetFloat(parameters, "outBlack", 0f);
var outWhite = GetFloat(parameters, "outWhite", 1f);
var gamma = GetFloat(parameters, "gamma", 1f);

// Per-channel controls (used when channel is a specific RGBA)
var rInBlack = GetFloat(parameters, "redInBlack", 0f);
var rInWhite = GetFloat(parameters, "redInWhite", 1f);
var rOutBlack = GetFloat(parameters, "redOutBlack", 0f);
var rOutWhite = GetFloat(parameters, "redOutWhite", 1f);
var rGamma = GetFloat(parameters, "redGamma", 1f);

var gInBlack = GetFloat(parameters, "greenInBlack", 0f);
var gInWhite = GetFloat(parameters, "greenInWhite", 1f);
var gOutBlack = GetFloat(parameters, "greenOutBlack", 0f);
var gOutWhite = GetFloat(parameters, "greenOutWhite", 1f);
var gGamma = GetFloat(parameters, "greenGamma", 1f);

var bInBlack = GetFloat(parameters, "blueInBlack", 0f);
var bInWhite = GetFloat(parameters, "blueInWhite", 1f);
var bOutBlack = GetFloat(parameters, "blueOutBlack", 0f);
var bOutWhite = GetFloat(parameters, "blueOutWhite", 1f);
var bGamma = GetFloat(parameters, "blueGamma", 1f);

var aInBlack = GetFloat(parameters, "alphaInBlack", 0f);
var aInWhite = GetFloat(parameters, "alphaInWhite", 1f);
var aOutBlack = GetFloat(parameters, "alphaOutBlack", 0f);
var aOutWhite = GetFloat(parameters, "alphaOutWhite", 1f);
var aGamma = GetFloat(parameters, "alphaGamma", 1f);

var result = input.Clone();

// Pre-compute per-channel level parameters based on active mode
float ibR, iwR, obR, owR, gR;
float ibG, iwG, obG, owG, gG;
float ibB, iwB, obB, owB, gB;
float ibA, iwA, obA, owA, gA;

switch (channel)
{
    case "red":
        ibR = rInBlack; iwR = rInWhite; obR = rOutBlack; owR = rOutWhite; gR = rGamma;
        ibG = inBlack; iwG = inWhite; obG = outBlack; owG = outWhite; gG = gamma;
        ibB = inBlack; iwB = inWhite; obB = outBlack; owB = outWhite; gB = gamma;
        ibA = inBlack; iwA = inWhite; obA = outBlack; owA = outWhite; gA = gamma;
        break;
    case "green":
        ibR = inBlack; iwR = inWhite; obR = outBlack; owR = outWhite; gR = gamma;
        ibG = gInBlack; iwG = gInWhite; obG = gOutBlack; owG = gOutWhite; gG = gGamma;
        ibB = inBlack; iwB = inWhite; obB = outBlack; owB = outWhite; gB = gamma;
        ibA = inBlack; iwA = inWhite; obA = outBlack; owA = outWhite; gA = gamma;
        break;
    case "blue":
        ibR = inBlack; iwR = inWhite; obR = outBlack; owR = outWhite; gR = gamma;
        ibG = inBlack; iwG = inWhite; obG = outBlack; owG = outWhite; gG = gamma;
        ibB = bInBlack; iwB = bInWhite; obB = bOutBlack; owB = bOutWhite; gB = bGamma;
        ibA = inBlack; iwA = inWhite; obA = outBlack; owA = outWhite; gA = gamma;
        break;
    case "alpha":
        ibR = inBlack; iwR = inWhite; obR = outBlack; owR = outWhite; gR = gamma;
        ibG = inBlack; iwG = inWhite; obG = outBlack; owG = outWhite; gG = gamma;
        ibB = inBlack; iwB = inWhite; obB = outBlack; owB = outWhite; gB = gamma;
        ibA = aInBlack; iwA = aInWhite; obA = aOutBlack; owA = aOutWhite; gA = aGamma;
        break;
    default: // RGB
        ibR = inBlack; iwR = inWhite; obR = outBlack; owR = outWhite; gR = gamma;
        ibG = inBlack; iwG = inWhite; obG = outBlack; owG = outWhite; gG = gamma;
        ibB = inBlack; iwB = inWhite; obB = outBlack; owB = outWhite; gB = gamma;
        ibA = inBlack; iwA = inWhite; obA = outBlack; owA = outWhite; gA = gamma;
        break;
}

result.Apply((r, g, b, a) =>
{
    r = ApplyLevels(r, ibR, iwR, obR, owR, gR);
    g = ApplyLevels(g, ibG, iwG, obG, owG, gG);
    b = ApplyLevels(b, ibB, iwB, obB, owB, gB);
    a = ApplyLevels(a, ibA, iwA, obA, owA, gA);
    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), Math.Clamp(a, 0f, 1f));
});

return result;


/// <summary>
/// Applies a single-channel levels adjustment:
///   1. Clamp input to [inBlack, inWhite]
///   2. Normalize to [0, 1]
///   3. Apply gamma (power law)
///   4. Map to output range [outBlack, outWhite]
/// </summary>
private static float ApplyLevels(float val, float inBlack, float inWhite, float outBlack, float outWhite, float gammaVal)
{
    // Guard degenerate range
    if (inWhite <= inBlack) return outBlack;

    // Clamp to input range
    val = Math.Clamp(val, inBlack, inWhite);

    // Normalize to [0, 1]
    val = (val - inBlack) / (inWhite - inBlack);

    // Apply gamma (gamma = 1 is identity; < 1 brightens mid-tones; > 1 darkens)
    var invGamma = 1f / MathF.Max(0.001f, gammaVal);
    val = MathF.Pow(val, invGamma);

    // Map to output range
    val = outBlack + val * (outWhite - outBlack);

    return val;
}
